import React, { useState, useEffect } from 'react';
import './styles/App.css';
import Terminal from './functions/Terminal';
import ResumeContent from './functions/ResumeContent';
import ReactGithubList from './ReactGithubList/react-github-widget';

const App = () => {
  const [activeApp, setActiveApp] = useState(null);

  useEffect(() => {

  }, []);

  const handleTerminalClick = (appName) => {
    setActiveApp(appName);
  };

  const closeTerminal = () => {
    setActiveApp(null);
  };

  const renderTerminalContent = () => {
    switch (activeApp) {
      case 'html':
        return (
          <>
            <span className="terminal-line">Website.html</span>
            <span className="terminal-line">----------------------</span>
            <span className="terminal-line">&lt;!DOCTYPE html&gt;</span>
            <span className="terminal-line">&lt;html&gt;</span>
            <span className="terminal-line">  &lt;head&gt;</span>
            <span className="terminal-line">    &lt;title&gt;My HTML Project&lt;/title&gt;</span>
            <span className="terminal-line">  &lt;/head&gt;</span>
            <span className="terminal-line">  &lt;body&gt;</span>
            <span className="terminal-line">    &lt;h1&gt;Hello, HTML!&lt;/h1&gt;</span>
            <span className="terminal-line">  &lt;/body&gt;</span>
            <span className="terminal-line">&lt;/html&gt;</span>
          </>
        );
      case 'css':
        return (
          <>
            <span className="terminal-line">styles.css</span>
            <span className="terminal-line">-------------------</span>
            <span className="terminal-line">h1 &#123;</span>
            <span className="terminal-line">  color: blue;</span>
            <span className="terminal-line">  font-size: 24px;</span>
            <span className="terminal-line">&#125;</span>
          </>
        );
      case 'php':
        return (
          <>
            <span className="terminal-line">index.php</span>
            <span className="terminal-line">----------------</span>
            <span className="terminal-line">&lt;?php</span>
            <span className="terminal-line">  echo "Hello, PHP!";</span>
            <span className="terminal-line">?&gt;</span>
          </>
        );
      // Add more cases for other coding languages
      default:
        return null;
    }
  };

  return (
    <div className="App">
      <header className="App-header">
        <Terminal activeApp={activeApp} onClose={closeTerminal} />
        <div className="terminal-container">
          <div className="terminal-option" onClick={() => handleTerminalClick('html')}>
            HTML
          </div>
          <div className="terminal-option" onClick={() => handleTerminalClick('css')}>
            CSS
          </div>
          <div className="terminal-option" onClick={() => handleTerminalClick('php')}>
            PHP
          </div>
          {/* Add more terminal options for other coding languages */}
        </div>
        {activeApp && (
          <div className="terminal-content">
            {renderTerminalContent()}
          </div>
        )}
      </header>
    </div>
  );
};

export default App;
